import {
  successResponse,
  fromNeverthrowError,
  outputAndExit,
} from '@/cli/output';

import { getWalletOrExit } from '../lib/get-wallet-or-exit';

import {
  getBalances,
  listAccountsWithAddresses,
  listAccountsWithBalances,
} from '@/operations/wallet';
import { redeemInviteCode } from '@/shared/redeem-invite';
import { maybeRefreshFirstPartySkill } from '@/shared/skills/first-party';

import type { Command, GlobalFlags } from '@/types';
import type { RedeemInviteArgs } from '@/shared/redeem-invite';

const SURFACE = 'cli:wallet';

export const getBalanceCommand: Command = async args => {
  const wallets = await getWalletOrExit(args);
  const { totalBalance, onboardingCta } = await getBalances(
    SURFACE,
    wallets,
    args
  );

  return outputAndExit(
    successResponse({
      balance: totalBalance,
      onboardingCta,
    }),
    args
  );
};

export const listAccountsCommand: Command = async args => {
  const wallets = await getWalletOrExit(args);
  const result = await listAccountsWithBalances(SURFACE, wallets, args);
  return outputAndExit(successResponse(result), args);
};

export const walletRedeemCommand: Command<RedeemInviteArgs> = async args => {
  const wallets = await getWalletOrExit(args);

  const result = await redeemInviteCode(SURFACE, args, args, wallets);

  if (result.isErr()) {
    return outputAndExit(fromNeverthrowError(result), args);
  }

  return outputAndExit(
    successResponse({
      redeemed: true,
      amount: `$${result.value.amount}`,
      txHash: result.value.txHash,
    }),
    args
  );
};

export const legacyWalletInfoCommand: Command = async args => {
  await maybeRefreshFirstPartySkill('agentcash', args);
  outputLegacyWalletMigration(
    args,
    [
      '`agentcash wallet info` has been removed.',
      'Use `agentcash balance` for total funds.',
      'Use `agentcash accounts` for network-specific addresses and deposit links.',
    ].join('\n')
  );
};

export const legacyWalletBalanceCommand: Command = async args => {
  await maybeRefreshFirstPartySkill('agentcash', args);
  outputLegacyWalletMigration(
    args,
    [
      '`agentcash wallet balance` has been removed.',
      'Use `agentcash balance` instead.',
    ].join('\n')
  );
};

export const legacyWalletRedeemCommand: Command<
  RedeemInviteArgs
> = async args => {
  await maybeRefreshFirstPartySkill('agentcash', args);
  outputLegacyWalletMigration(
    args,
    [
      '`agentcash wallet redeem <code>` has been removed.',
      `Use \`agentcash redeem ${args.code}\` instead.`,
    ].join('\n')
  );
};

export const legacyWalletAddressCommand: Command = async args => {
  const wallets = await getWalletOrExit(args);
  const result = listAccountsWithAddresses(wallets);
  return outputAndExit(successResponse(result), args);
};

function outputLegacyWalletMigration(
  flags: GlobalFlags,
  message: string
): never {
  return outputAndExit(
    successResponse({
      migrated: true,
      message,
    }),
    flags
  );
}
