import * as os from 'node:os';
import * as path from 'node:path';

import chalk from 'chalk';
import yaml from 'js-yaml';
import z from 'zod';

import { log } from '@/shared/log';
import { safeReadFile } from '@/shared/neverthrow/fs';
import { installGitHubSkill } from '@/shared/skills/github';

import type { GlobalFlags } from '@/types';

export const FIRST_PARTY_SKILL_VERSION_FIELD = 'version';
const installedSkillFrontmatterSchema = z
  .looseObject({
    metadata: z.object({
      [FIRST_PARTY_SKILL_VERSION_FIELD]: z
        .union([z.number().int().nonnegative(), z.string().regex(/^\d+$/)])
        .transform(value =>
          typeof value === 'number' ? value : Number.parseInt(value)
        ),
    }),
  })
  .transform(data => data.metadata[FIRST_PARTY_SKILL_VERSION_FIELD]);

const FIRST_PARTY_SKILLS = {
  agentcash: {
    source: {
      owner: 'merit-systems',
      repo: 'agentcash-skills',
      skillPath: 'skills/agentcash',
    },
    version: 2,
  },
};

interface RefreshFirstPartySkillResult {
  error?: string;
  skillPath: string;
  status: 'failed' | 'missing' | 'refreshed' | 'up_to_date';
  version: number | null;
}

export async function maybeRefreshFirstPartySkill(
  skillName: keyof typeof FIRST_PARTY_SKILLS,
  flags: GlobalFlags
): Promise<RefreshFirstPartySkillResult> {
  const spec = FIRST_PARTY_SKILLS[skillName];
  const skillPath = path.join(
    os.homedir(),
    '.agents',
    'skills',
    skillName,
    'SKILL.md'
  );
  const readResult = await safeReadFile('skill-refresh', skillPath);

  if (readResult.isErr()) {
    if (readResult.error.cause === 'file_not_found') {
      return {
        skillPath,
        status: 'missing',
        version: null,
      };
    }

    const message = `Failed to read installed ${skillName} skill: ${readResult.error.message}`;
    warnSkillRefresh(flags, message);

    return {
      error: message,
      skillPath,
      status: 'failed',
      version: null,
    };
  }

  const version = parseInstalledSkillVersion(readResult.value);
  if (version !== null && version >= spec.version) {
    return {
      skillPath,
      status: 'up_to_date',
      version,
    };
  }

  const installResult = await installGitHubSkill('skill-refresh', spec.source);

  if (installResult.isErr()) {
    const message = `Failed to refresh installed ${skillName} skill: ${installResult.error.message}`;
    warnSkillRefresh(flags, message);

    return {
      error: message,
      skillPath,
      status: 'failed',
      version,
    };
  }

  return {
    skillPath,
    status: 'refreshed',
    version: spec.version,
  };
}

export function parseInstalledSkillVersion(skillMd: string) {
  const frontmatterMatch = /^---\s*\n([\s\S]*?)\n---(?:\s*\n|$)/.exec(skillMd);
  if (!frontmatterMatch) return null;

  const frontmatter = yaml.load(frontmatterMatch[1] ?? '');
  const frontmatterResult =
    installedSkillFrontmatterSchema.safeParse(frontmatter);
  if (!frontmatterResult.success) return null;

  return frontmatterResult.data;
}

function warnSkillRefresh(flags: GlobalFlags, message: string) {
  log.error(message);

  if (flags.quiet) return;
  if (!flags.verbose && !process.stderr.isTTY) return;

  process.stderr.write(chalk.yellow(`Warning: ${message}\n`));
}
